<template><div class="workspace-page"><section class="page-intro"><div><p>机构套餐治理</p><h2>审核记录</h2><span>管理员只负责审批机构套餐变更，不能直接新增、编辑或上下架套餐。</span></div></section><el-card shadow="never"><el-select v-model="status" @change="load"><el-option label="全部状态" value=""/><el-option label="待审核" value="pending"/><el-option label="已通过" value="approved"/><el-option label="已驳回" value="rejected"/><el-option label="已撤回" value="withdrawn"/></el-select><el-table :data="items" v-loading="loading" empty-text="暂无审核记录"><el-table-column label="机构" min-width="190"><template #default="s">{{s.row.institution?.name}} · {{s.row.institution?.branch_name}}</template></el-table-column><el-table-column prop="package_name" label="套餐" min-width="150"/><el-table-column label="操作" width="100"><template #default="s">{{actionLabel(s.row.action)}}</template></el-table-column><el-table-column label="状态" width="100"><template #default="s"><el-tag :type="statusType(s.row.status)">{{statusLabel(s.row.status)}}</el-tag></template></el-table-column><el-table-column label="变更内容" min-width="260"><template #default="s"><span class="table-json">{{summary(s.row)}}</span></template></el-table-column><el-table-column label="处理" width="150"><template #default="s"><template v-if="s.row.status==='pending'"><el-button link type="success" @click="approve(s.row)">通过</el-button><el-button link type="danger" @click="reject(s.row)">驳回</el-button></template><span v-else>{{s.row.review_note||"—"}}</span></template></el-table-column></el-table></el-card></div></template>
<script setup>import{onMounted,ref}from"vue";import{ElMessage,ElMessageBox}from"element-plus";import{approveAdminPackageChangeRequest,fetchAdminPackageChangeRequests,rejectAdminPackageChangeRequest}from"../../api/admin";const items=ref([]),loading=ref(false),status=ref("");const actionLabel=(v)=>({create:"新增",update:"修改",deactivate:"下架",reactivate:"恢复"}[v]||v);const statusLabel=(v)=>({pending:"待审核",approved:"已通过",rejected:"已驳回",withdrawn:"已撤回"}[v]||v);const statusType=(v)=>({approved:"success",rejected:"danger",withdrawn:"info",pending:"warning"}[v]);const summary=(row)=>{const d=row.proposed_data||{};return `${d.name||row.package_name||"套餐"}｜${d.focus_area||"—"}｜¥${Number(d.price||0).toFixed(2)}｜${d.is_active===false?"下架":"启用"}`;};async function load(){loading.value=true;try{items.value=(await fetchAdminPackageChangeRequests(status.value?{status:status.value}:{})).data.items||[];}finally{loading.value=false;}}async function approve(item){try{await ElMessageBox.confirm("通过后变更会立即应用到机构当前套餐，确认通过？","通过申请",{type:"warning"});await approveAdminPackageChangeRequest(item.id);ElMessage.success("申请已通过并生效");await load();}catch(error){if(error!=="cancel"&&error!=="close")ElMessage.error(error?.response?.data?.message||"审批失败");}}async function reject(item){try{const{value}=await ElMessageBox.prompt("可填写驳回说明（选填）","驳回申请",{inputType:"textarea",confirmButtonText:"确认驳回"});await rejectAdminPackageChangeRequest(item.id,value);ElMessage.success("申请已驳回");await load();}catch(error){if(error!=="cancel"&&error!=="close")ElMessage.error(error?.response?.data?.message||"驳回失败");}}onMounted(load);</script>
